  ('pukao-6f0ba476-moex-00132', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '下列向稅捐稽徵機關申請分期繳納稅款之情形，何者可以免計算利息？', '["應繳納之所得稅因客觀事實發生財務困難申請分期", "經稅捐稽徵機關查獲應補徵鉅額稅捐申請分期", "納稅義務人因天災、事變、不可抗力之事由申請分期", "經地方政府認定符合分期繳納之地價稅申請分期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00133', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '自113年度所得稅結算申報起，所得稅法有關幼兒學前扣除額之規定，下列何者正確？', '["納稅義務人有6歲以下之子女", "每人每年扣除額為12萬元", "股利按28%稅率分開計稅者不得適用", "屬於列舉扣除額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00134', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '自113年度所得稅結算申報起，所得稅法有關房屋租金支出之規定，下列何者錯誤？', '["屬特別扣除額", "指納稅義務人、配偶及受扶養直系親屬在中華民國境內租屋供自住者所支付的租金", "每一申報戶每年扣除數額以18萬元為限", "納稅義務人申報有購屋借款利息者不得列報扣除"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00135', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '稅捐稽徵法所稱相當擔保，下列何者正確？', '["銀行存款單摺，按存款本金額計值", "黃金，按八折計算", "經中央銀行掛牌之外幣、核准上市之有價證券，按九折計算", "政府發行經規定可十足提供公務擔保之公債，按其市值計算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
