  ('pukao-6f0ba476-moex-00137', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '下列有關兼營營業人年終調整營業稅額之規定，何者錯誤？', '["於每年1月15日以前辦理上一年度最後一期調整申報", "當年度實際營業期間未滿9個月者，免辦理調整申報", "不論採直接扣抵法或間接扣抵法者，皆要辦理調整申報", "採間接扣抵法之兼營營業人辦理調整申報，應經會計師或稅務代理人查核簽證"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "b003c15e813e", "answer_pdf_sha1": "d0463ac566fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
